"""
adapters/base.py — Read-Only Source Adapter Protocol

Any upstream vector database can serve as the static chunk source by
implementing SourceAdapter.  PrismResonance never calls write methods
on the source — it is a read-only lens.
"""

from __future__ import annotations

from abc import ABC, abstractmethod
from dataclasses import dataclass, field
from typing import Iterator, List, Optional

import numpy as np


@dataclass
class ChunkRecord:
    """A single chunk as returned by a SourceAdapter."""
    chunk_id:  str
    text:      str
    vector:    np.ndarray            # (N,) float32 — base embedding amplitude
    metadata:  dict = field(default_factory=dict)
    namespace: str  = ""


class SourceAdapter(ABC):
    """
    Read-only interface to an upstream vector store.

    Implement this to connect PrismResonance to any source:
    Chroma, pgvector, Pinecone, FAISS, Weaviate, custom stores, etc.

    PrismResonance will ONLY call:
      - fetch(ids)          for targeted lookups
      - scan_batches()      for full-corpus scans (ingestion / rehydration)
      - count()             for sizing
    """

    @abstractmethod
    def fetch(self, chunk_ids: List[str]) -> List[ChunkRecord]:
        """Return records for the given IDs. Missing IDs are silently skipped."""

    @abstractmethod
    def scan_batches(
        self,
        batch_size: int = 256,
        namespace: str = "",
    ) -> Iterator[List[ChunkRecord]]:
        """Yield all records in batches. Used for initial ingestion."""

    @abstractmethod
    def count(self, namespace: str = "") -> int:
        """Total number of chunks in the source."""

    def fetch_vectors(self, chunk_ids: List[str]) -> np.ndarray:
        """
        Convenience: return stacked (M, N) float32 matrix for given IDs.
        Preserves input order; raises KeyError if any ID is missing.
        """
        records = {r.chunk_id: r for r in self.fetch(chunk_ids)}
        missing = [cid for cid in chunk_ids if cid not in records]
        if missing:
            raise KeyError(f"Chunk IDs not found in source: {missing[:5]}")
        return np.stack([records[cid].vector for cid in chunk_ids], axis=0)
